        _loading = true;
        try
        {
            _savedProfile = await SettingsService.GetProfileAsync();
            ApplyProfile(_savedProfile);
        }
        finally
        {
            _loading = false;
        }
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            _message = "Profile saved successfully!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save profile: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _message = null;
        }
    }
}
"}

{"path": "/tmp/sv-327c290efd4442a6ae3eaafbc7c437c4/Components/Settings/NotificationsSection.razor", "file_text": "@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Notification Preferences</h3>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="card mb-4">
            <div class="card-body">
                <h5 class="card-title mb-3">General</h5>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="emailNotif"
                           checked="@_emailNotifications"
                           @onchange="e => _emailNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="emailNotif">
                        Email Notifications
                        <small class="d-block text-muted">Receive notifications via email</small>
                    </label>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="pushNotif"
                           checked="@_pushNotifications"
                           @onchange="e => _pushNotifications = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="pushNotif">
                        Push Notifications
                        <small class="d-block text-muted">Receive push notifications in your browser</small>
                    </label>
                </div>

                <div class="form-check form-switch mb-3">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest"
                           checked="@_weeklyDigest"
                           @onchange="e => _weeklyDigest = (bool)(e.Value ?? false)" />
                    <label class="form-check-label" for="weeklyDigest">
                        Weekly Digest
                        <small class="d-block text-muted">Get a weekly summary of activity</small>
                    </label>
                </div>
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-body">
                <h5 class="card-title mb-3">Muted Channels</h5>
                @if (_allChannels.Count == 0)
                {
                    <p class="text-muted">No channels available.</p>
                }
                else
                {
                    @foreach (var channel in _allChannels)
                    {
                        <div class="form-check mb-2">
                            <input class="form-check-input" type="checkbox" id="@($"ch-{channel}")"
                                   checked="@_mutedChannels.Contains(channel)"
                                   @onchange="e => ToggleMute(channel, (bool)(e.Value ?? false))" />
                            <label class="form-check-label" for="@($"ch-{channel}")">
                                @channel
                            </label>
                        </div>
                    }
                }
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save Preferences
        </button>
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _allChannels = new();

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var prefs = await SettingsService.GetNotificationPrefsAsync();
            _emailNotifications = prefs.EmailNotifications;
            _pushNotifications = prefs.PushNotifications;
            _weeklyDigest = prefs.WeeklyDigest;
            _mutedChannels = new HashSet<string>(prefs.MutedChannels);
            _allChannels = new List<string>(prefs.MutedChannels);

            // Ensure we show some channels even if none are muted
            if (_allChannels.Count == 0)
            {
                _allChannels = new List<string> { "general", "announcements", "random", "support", "engineering" };
            }
        }
        finally
        {
            _loading = false;
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications,
                _pushNotifications,
                _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            _message = "Notification preferences saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

{"path": "/tmp/sv-327c290efd4442a6ae3eaafbc7c437c4/Components/Settings/ChangePasswordPanel.razor", "file_text": "@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => _expanded = !_expanded"
         style="cursor:pointer;">
        <h5 class="mb-0">🔑 Change Password</h5>
        <span class="@(_expanded ? "rotate-icon" : "")">▶</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control"
                       @bind="_confirmPassword" />
                @if (!string.IsNullOrEmpty(_confirmPassword) && _newPassword != _confirmPassword)
                {
                    <div class="text-danger small mt-1">Passwords do not match.</div>
                }
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync"
                    disabled="@(!CanSubmit)">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private bool CanSubmit =>
        !_saving
        && !string.IsNullOrWhiteSpace(_currentPassword)
        && !string.IsNullOrWhiteSpace(_newPassword)
        && _newPassword == _confirmPassword;

    private async Task UpdatePasswordAsync()
    {
        if (!CanSubmit) return;

        _saving = true;
        _message = null;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully!";
            _messageIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to change password: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

{"path": "/tmp/sv-327c290efd4442a6ae3eaafbc7c437c4/Components/Settings/ActiveSessionsTable.razor", "file_text": "@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title mb-3">📱 Active Sessions</h5>

        @if (Sessions is null || Sessions.Count == 0)
        {
            <p class="text-muted">No active sessions found.</p>
        }
        else
        {
            <div class="table-responsive">
                <table class="table table-hover align-middle">
                    <thead class="table-light">
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @foreach (var session in Sessions)
                        {
                            var isCurrent = session.Id == CurrentSessionId;
                            <tr>
                                <td>
                                    @session.Device
                                    @if (isCurrent)
                                    {
                                        <span class="badge bg-success ms-1">Current</span>
                                    }
                                </td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (!isCurrent)
                                    {
                                        <button class="btn btn-outline-danger btn-sm"
                                                @onclick="() => RequestRevoke(session)">
                                            Revoke
                                        </button>
                                    }
                                </td>
                            </tr>
                        }
                    </tbody>
                </table>
            </div>
        }
    </div>
</div>

@* Confirmation dialog *@
@if (_sessionToRevoke is not null)
{
    <div class="modal d-block" tabindex="-1" style="background:rgba(0,0,0,0.5);">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public List<ActiveSession>? Sessions { get; set; }
    [Parameter] public string? CurrentSessionId { get; set; }
    [Parameter] public EventCallback<string> OnRevokeSession { get; set; }

    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        try
        {
            await OnRevokeSession.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
        finally
        {
            _revoking = false;
        }
    }
}
"}

{"path": "/tmp/sv-327c290efd4442a6ae3eaafbc7c437c4/Components/Settings/SecuritySection.razor", "file_text": "@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Security Settings</h3>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />

        <div class="card mb-4">
            <div class="card-body">
                <h5 class="card-title mb-3">🛡️ Two-Factor Authentication</h5>
                <div class="d-flex align-items-center gap-3">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="twoFactor">
                            Enable Two-Factor Authentication
                        </label>
                    </div>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="text-muted small mt-2 mb-0">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </p>
                }
            </div>
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevokeSession="HandleRevokeSessionAsync" />

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string? _currentSessionId;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = settings.Sessions.ToList();
            // Treat the first session as "current" for demo purposes
            _currentSessionId = _sessions.FirstOrDefault()?.Id;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevokeSessionAsync(string sessionId)
    {
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions.RemoveAll(s => s.Id == sessionId);
            _message = "Session revoked successfully.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
    }
}
"}

{"path": "/tmp/sv-327c290efd4442a6ae3eaafbc7c437c4/Components/Settings/AppearanceSection.razor", "file_text": "@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Appearance Settings</h3>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
