@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => _expanded = !_expanded"
         style="cursor:pointer;">
        <h5 class="mb-0">🔑 Change Password</h5>
        <span class="@(_expanded ? "rotate-icon" : "")">▶</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control"
                       @bind="_confirmPassword" />
                @if (!string.IsNullOrEmpty(_confirmPassword) && _newPassword != _confirmPassword)
                {
                    <div class="text-danger small mt-1">Passwords do not match.</div>
                }
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_message
                    <button type="button" class="btn-close" @onclick="() => _message = null"></button>
                </div>
            }

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync"
                    disabled="@(!CanSubmit)">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private bool CanSubmit =>
        !_saving
        && !string.IsNullOrWhiteSpace(_currentPassword)
        && !string.IsNullOrWhiteSpace(_newPassword)
        && _newPassword == _confirmPassword;

    private async Task UpdatePasswordAsync()
    {
        if (!CanSubmit) return;

        _saving = true;
        _message = null;
        try
        {
            await OnChangePassword.InvokeAsync((_currentPassword, _newPassword));
            _message = "Password updated successfully!";
            _messageIsError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _message = $"Failed to change password: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

