@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Security Settings</h3>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <ChangePasswordPanel OnChangePassword="HandleChangePasswordAsync" />

        <div class="card mb-4">
            <div class="card-body">
                <h5 class="card-title mb-3">🛡️ Two-Factor Authentication</h5>
                <div class="d-flex align-items-center gap-3">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@_twoFactorEnabled"
                               @onchange="e => _twoFactorEnabled = (bool)(e.Value ?? false)" />
                        <label class="form-check-label" for="twoFactor">
                            Enable Two-Factor Authentication
                        </label>
                    </div>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                @if (_lastPasswordChange.HasValue)
                {
                    <p class="text-muted small mt-2 mb-0">
                        Last password change: @_lastPasswordChange.Value.ToString("MMMM dd, yyyy")
                    </p>
                }
            </div>
        </div>

        <ActiveSessionsTable Sessions="_sessions"
                             CurrentSessionId="@_currentSessionId"
                             OnRevokeSession="HandleRevokeSessionAsync" />

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }
    }
</div>

@code {
    private bool _loading = true;
    private bool _twoFactorEnabled;
    private DateTime? _lastPasswordChange;
    private List<ActiveSession> _sessions = new();
    private string? _currentSessionId;
    private string? _message;
    private bool _messageIsError;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetSecuritySettingsAsync();
            _twoFactorEnabled = settings.TwoFactorEnabled;
            _lastPasswordChange = settings.LastPasswordChange;
            _sessions = settings.Sessions.ToList();
            // Treat the first session as "current" for demo purposes
            _currentSessionId = _sessions.FirstOrDefault()?.Id;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        _lastPasswordChange = DateTime.UtcNow;
    }

    private async Task HandleRevokeSessionAsync(string sessionId)
    {
        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            _sessions.RemoveAll(s => s.Id == sessionId);
            _message = "Session revoked successfully.";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to revoke session: {ex.Message}";
            _messageIsError = true;
        }
    }
}

