@namespace sv_327c290efd4442a6ae3eaafbc7c437c4.Components.Settings
@using sv_327c290efd4442a6ae3eaafbc7c437c4.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Appearance Settings</h3>

    @if (_loading)
    {
        <div class="text-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="card mb-4">
                    <div class="card-body">
                        <h5 class="card-title mb-3">🎨 Theme</h5>
                        @foreach (var theme in new[] { ("Light", "light"), ("Dark", "dark"), ("System", "system") })
                        {
                            <div class="form-check mb-2">
                                <input class="form-check-input" type="radio" name="theme"
                                       id="@($"theme-{theme.Item2}")"
                                       value="@theme.Item2"
                                       checked="@(_theme == theme.Item2)"
                                       @onchange="() => _theme = theme.Item2" />
                                <label class="form-check-label" for="@($"theme-{theme.Item2}")">
                                    @theme.Item1
                                </label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <h5 class="card-title mb-3">🔤 Font Size</h5>
                        @foreach (var size in new[] { ("Small", "small"), ("Medium", "medium"), ("Large", "large") })
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize"
                                       id="@($"fs-{size.Item2}")"
                                       value="@size.Item2"
                                       checked="@(_fontSize == size.Item2)"
                                       @onchange="() => _fontSize = size.Item2" />
                                <label class="form-check-label" for="@($"fs-{size.Item2}")">
                                    @size.Item1
                                </label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <h5 class="card-title mb-3">🌐 Language</h5>
                        <select class="form-select" @bind="_language">
                            <option value="en">English</option>
                            <option value="es">Español</option>
                            <option value="fr">Français</option>
                            <option value="de">Deutsch</option>
                            <option value="ja">日本語</option>
                            <option value="zh">中文</option>
                        </select>
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <h5 class="card-title mb-3">📐 Compact Mode</h5>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode"
                                   checked="@_compactMode"
                                   @onchange="e => _compactMode = (bool)(e.Value ?? false)" />
                            <label class="form-check-label" for="compactMode">
                                Enable compact mode
                                <small class="d-block text-muted">Reduces spacing and padding throughout the UI</small>
                            </label>
                        </div>
                    </div>
                </div>
            </div>

            <div class="col-md-5">
                <div class="card sticky-top" style="top:1rem;">
                    <div class="card-header">
                        <h5 class="mb-0">👁️ Live Preview</h5>
                    </div>
                    <div class="card-body @PreviewClasses" style="@PreviewStyle">
                        <h6 style="@PreviewFontStyle">Sample Heading</h6>
                        <p style="@PreviewFontStyle" class="@(_compactMode ? "mb-1" : "mb-3")">
                            This is how your content will appear with the selected settings.
                        </p>
                        <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-3")">
                            <button class="btn btn-sm btn-primary" style="@PreviewFontStyle">Primary</button>
                            <button class="btn btn-sm btn-outline-secondary" style="@PreviewFontStyle">Secondary</button>
                        </div>
                        <div class="@(_compactMode ? "p-1" : "p-2") rounded" style="@PreviewCardStyle">
                            <small style="@PreviewFontStyle">
                                Theme: <strong>@_theme</strong> ·
                                Font: <strong>@_fontSize</strong> ·
                                Lang: <strong>@_language</strong> ·
                                Compact: <strong>@(_compactMode ? "On" : "Off")</strong>
                            </small>
                        </div>
                    </div>
                </div>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <button class="btn btn-primary mt-2" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Save
        </button>
    }
</div>

@code {
    private string _theme = "light";
    private string _fontSize = "medium";
    private string _language = "en";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private string PreviewClasses => _theme == "dark" ? "text-white" : "";

    private string PreviewStyle => _theme switch
    {
        "dark" => "background:#1e1e1e; color:#d4d4d4; transition: all 0.3s;",
        "system" => "background:#f0f0f0; color:#333; border-left: 3px solid #0d6efd; transition: all 0.3s;",
        _ => "background:#ffffff; color:#212529; transition: all 0.3s;"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "small" => "font-size:0.8rem;",
        "large" => "font-size:1.2rem;",
        _ => "font-size:1rem;"
    };

    private string PreviewCardStyle => _theme switch
    {
        "dark" => "background:#2d2d2d;",
        _ => "background:#e9ecef;"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _message = "Appearance settings saved!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

