    private string _activeSection = "profile";
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 80vh;
}

::deep .settings-sidebar {
    min-width: 220px;
    max-width: 240px;
    background: #f8f9fa;
    border-radius: 0.5rem;
    padding: 0.5rem 0;
    align-self: flex-start;
    position: sticky;
    top: 1rem;
}

::deep .settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0;
    padding: 0.6rem 1rem;
    border-left: 3px solid transparent;
    transition: all 0.15s ease;
}

::deep .settings-sidebar .nav-link:hover {
    background: #e9ecef;
    color: #212529;
}

::deep .settings-sidebar .nav-link.active {
    background: #e7f1ff;
    color: #0d6efd;
    border-left-color: #0d6efd;
    font-weight: 600;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

::deep .settings-section h3 {
    border-bottom: 2px solid #e9ecef;
    padding-bottom: 0.75rem;
}

::deep .rotate-icon {
    display: inline-block;
    transform: rotate(90deg);
    transition: transform 0.2s ease;
}

